+unsafe fn is_zeroed_gaicb_request(req: *mut c_void) -> bool {
+    if req.is_null() {
+        return false;
+    }
+    // SAFETY: `req` is a caller-provided pointer. We only read the first four
+    // pointer-sized fields, which match glibc's public `gaicb` request-shape
